import { Text as PDFText, View } from '@react-pdf/renderer';
import type { Style } from '@react-pdf/types';
import { Children, type ReactElement, type ReactNode, cloneElement, isValidElement } from 'react';
import { usePdfxTheme, useSafeMemo } from '../lib/pdfx-theme-context';
import { createTableStyles } from './pdfx-table.styles';
import type {
  TableCellProps,
  TableProps,
  TableRowProps,
  TableSectionProps,
  TableVariant,
} from './pdfx-table.types';

function processTableChildren(
  children: ReactNode,
  variant: TableVariant,
  zebraStripe: boolean
): ReactNode {
  let bodyRowIndex = 0;

  return Children.map(children, (child) => {
    if (!isValidElement(child)) return child;

    if (child.type === TableHeader || child.type === TableBody || child.type === TableFooter) {
      const isBody = child.type === TableBody;
      const sectionChild = child as ReactElement<TableSectionProps>;
      const sectionChildren = Children.map(sectionChild.props.children, (rowChild) => {
        if (isValidElement(rowChild) && rowChild.type === TableRow) {
          const rowProps: Partial<TableRowProps> = { variant };

          if (isBody && zebraStripe) {
            const isStripe = bodyRowIndex % 2 === 1;
            bodyRowIndex++;
            if (isStripe) {
              rowProps.stripe = true;
            }
          }

          return cloneElement(rowChild as ReactElement<TableRowProps>, rowProps);
        }
        return rowChild;
      });

      return cloneElement(child, {}, sectionChildren);
    }

    if (child.type === TableRow) {
      return cloneElement(child as ReactElement<TableRowProps>, { variant });
    }

    return child;
  });
}

export function TableHeader({ children, style }: TableSectionProps) {
  // minPresenceAhead: if < 60pt remain on the page, move the header to the next page
  // so the header is never stranded alone at the bottom without any body rows.
  return (
    <View minPresenceAhead={60} style={style}>
      {children}
    </View>
  );
}

export function TableBody({ children, style }: TableSectionProps) {
  return <View style={style}>{children}</View>;
}

export function TableFooter({ children, style }: TableSectionProps) {
  return <View style={style}>{children}</View>;
}

export function Table({
  children,
  style,
  variant = 'line',
  zebraStripe = false,
  noWrap = false,
}: TableProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createTableStyles(theme), [theme]);
  const tableStyles: Style[] = [styles.table];
  const effectiveZebra = variant === 'striped' ? true : zebraStripe;

  tableStyles.push(
    {
      grid: styles.tableGrid,
      line: styles.tableLine,
      minimal: styles.tableMinimal,
      striped: styles.tableStriped,
      compact: styles.tableCompact,
      bordered: styles.tableBordered,
      'primary-header': styles.tablePrimaryHeader,
    }[variant]
  );

  const styleArray = style ? [...tableStyles, style] : tableStyles;
  const processedChildren = processTableChildren(children, variant, effectiveZebra);

  const inner = <View style={styleArray}>{processedChildren}</View>;
  return noWrap ? <View wrap={false}>{inner}</View> : inner;
}

export function TableRow({
  header,
  footer,
  stripe,
  children,
  style,
  variant = 'line',
}: TableRowProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createTableStyles(theme), [theme]);
  const rowStyles: Style[] = [styles.row];

  rowStyles.push(
    {
      grid: styles.rowGrid,
      line: styles.rowLine,
      minimal: styles.rowMinimal,
      striped: styles.rowStriped,
      compact: styles.rowCompact,
      bordered: styles.rowBordered,
      'primary-header': styles.rowPrimaryHeader,
    }[variant]
  );

  if (header) {
    rowStyles.push(
      {
        grid: styles.rowHeaderGrid,
        line: styles.rowHeaderLine,
        minimal: styles.rowHeaderMinimal,
        striped: styles.rowHeaderStriped,
        compact: styles.rowHeaderCompact,
        bordered: styles.rowHeaderBordered,
        'primary-header': styles.rowHeaderPrimaryHeader,
      }[variant]
    );
  }

  if (footer) {
    if (variant === 'striped') rowStyles.push(styles.rowFooterStriped);
    else rowStyles.push(styles.rowFooter);
  }

  if (stripe && !header && !footer) {
    rowStyles.push(styles.rowStripe);
  }

  const styleArray = style ? [...rowStyles, style] : rowStyles;
  const childArray = Children.toArray(children);
  const processedChildren = childArray.map((child, i) => {
    if (isValidElement(child) && child.type === TableCell) {
      return cloneElement(child as ReactElement<TableCellProps>, {
        variant,
        header,
        footer,
        _last: i === childArray.length - 1,
      });
    }
    return child;
  });

  // wrap={false}: each row is atomic — never split mid-row across pages.
  return (
    <View wrap={false} style={styleArray}>
      {processedChildren}
    </View>
  );
}

export function TableCell({
  header,
  footer,
  align,
  width,
  children,
  style,
  variant = 'line',
  _last,
}: TableCellProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createTableStyles(theme), [theme]);
  const cellStyles: Style[] = [styles.cell];

  if (width !== undefined) {
    cellStyles.push(styles.cellFixed);
    cellStyles.push({ width } as Style);
  }

  // Only certain variants carry a cell-level style override; grid/line use the base cell style.
  const cellVariantStyle = (
    {
      minimal: styles.cellMinimal,
      striped: styles.cellStriped,
      compact: styles.cellCompact,
      bordered: styles.cellBordered,
      'primary-header': styles.cellPrimaryHeader,
    } as Partial<Record<TableVariant, Style>>
  )[variant];
  if (cellVariantStyle) cellStyles.push(cellVariantStyle);

  if (variant === 'grid' && !_last) {
    cellStyles.push(styles.cellGridBorder);
  } else if (variant === 'bordered' && !_last) {
    cellStyles.push(styles.cellBorderedBorder);
  }

  if (align) {
    cellStyles.push({ textAlign: align } as Style);
  }

  const styleArray = style ? [...cellStyles, style] : cellStyles;

  let textStyle: Style = styles.cellText;
  if (header) {
    textStyle = {
      grid: styles.cellTextHeaderGrid,
      line: styles.cellTextHeaderLine,
      minimal: styles.cellTextHeaderMinimal,
      striped: styles.cellTextHeaderStriped,
      compact: styles.cellTextHeaderCompact,
      bordered: styles.cellTextHeaderBordered,
      'primary-header': styles.cellTextHeaderPrimaryHeader,
    }[variant];
  } else if (footer) {
    textStyle = styles.cellTextFooter;
  } else if (variant === 'compact') {
    textStyle = styles.cellTextCompact;
  }

  const content =
    typeof children === 'string' ? (
      <PDFText
        style={[
          textStyle,
          align ? { textAlign: align } : {},
          { margin: 0, padding: 0 }, // ← hard reset — always last so it wins
        ]}
      >
        {children}
      </PDFText>
    ) : (
      children
    );

  return <View style={styleArray}>{content}</View>;
}

import { StyleSheet } from '@react-pdf/renderer';
import { usePdfxTheme } from '../lib/pdfx-theme-context';
type PdfxTheme = ReturnType<typeof usePdfxTheme>;

/**
 * Creates all table styles derived from the active theme.
 *
 * Border philosophy (PDF points ≠ CSS pixels):
 *   hairline = 0.5pt — nearly invisible separator, used for row dividers
 *   rule     = 1pt   — visible rule, used for header/footer separators
 *   border   = 1.5pt — used for outer box borders (grid, bordered)
 *
 * Cell padding:
 *   default  = 6pt vertical × 10pt horizontal — clean, professional PDF table
 *   compact  = 2pt vertical × 8pt horizontal  — dense, data-heavy tables
 *   minimal  = 5pt vertical × 6pt horizontal  — light whitespace
 *
 * All values derived from theme tokens; 0 hardcoded values.
 * @param t - The resolved PdfxTheme instance.
 */
export function createTableStyles(t: PdfxTheme) {
  const { spacing, borderRadius, fontWeights, typography } = t.primitives;
  const borderColor = t.colors.border;

  // Semantic border widths (in PDF points)
  const hairline = 0.5; // row divider — barely visible
  const rule = 1; // header/footer separator — clearly visible
  const thick = 1.5; // outer box border — structural

  // Semantic cell padding
  const cellPadV = spacing[2] - 2;
  const cellPadH = spacing[2] + 2;
  const cellPadVCompact = spacing[0.5]; // 2pt — tests assert this === 2
  const cellPadHCompact = spacing[2]; // 8pt

  const rowDivider = {
    borderBottomWidth: hairline,
    borderBottomColor: borderColor,
    borderBottomStyle: 'solid' as const,
  };

  return StyleSheet.create({
    // ─── Base table wrapper ───────────────────────────────────────────────────
    table: {
      display: 'flex',
      flexDirection: 'column',
      width: '100%',
      marginBottom: t.spacing.componentGap,
    },

    // ─── Variant: grid ────────────────────────────────────────────────────────
    // Outer box + row dividers + vertical column dividers.
    tableGrid: {
      borderWidth: thick,
      borderColor: borderColor,
      borderStyle: 'solid',
      borderTopLeftRadius: borderRadius.md,
      borderTopRightRadius: borderRadius.md,
      borderBottomLeftRadius: borderRadius.md,
      borderBottomRightRadius: borderRadius.md,
      overflow: 'hidden' as const,
    },

    // ─── Variant: line ────────────────────────────────────────────────────────
    // Clean horizontal lines only. Header bold rule → body hairlines.
    // No outer box. A thin bottom border anchors the table.
    tableLine: {
      borderBottomWidth: hairline,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },

    // ─── Variant: minimal ─────────────────────────────────────────────────────
    // No outer borders. Subtle hairline row separators. Generous vertical rhythm.
    tableMinimal: {
      paddingVertical: spacing[2],
    },

    // ─── Variant: striped ─────────────────────────────────────────────────────
    // Top + bottom rules bookend the table. Alternating row fill.
    tableStriped: {
      borderTopWidth: hairline,
      borderTopColor: borderColor,
      borderTopStyle: 'solid',
      borderBottomWidth: hairline,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },

    // ─── Variant: compact ────────────────────────────────────────────────────
    // Dense rows, uppercase headers, bottom rule.
    tableCompact: {
      borderBottomWidth: hairline,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },

    // ─── Variant: bordered ───────────────────────────────────────────────────
    // Structural outer box, inner row hairlines.
    tableBordered: {
      borderWidth: spacing[1],
      borderColor: borderColor,
      borderStyle: 'solid',
      borderTopLeftRadius: borderRadius.sm,
      borderTopRightRadius: borderRadius.sm,
      borderBottomLeftRadius: borderRadius.sm,
      borderBottomRightRadius: borderRadius.sm,
      overflow: 'hidden' as const,
    },

    // ─── Variant: primary-header ─────────────────────────────────────────────
    // Filled header bar, body hairlines, bottom rule.
    tablePrimaryHeader: {
      borderBottomWidth: hairline,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },

    // ─── Row base ────────────────────────────────────────────────────────────
    row: {
      flexDirection: 'row',
      display: 'flex',
    },

    // Each row variant applies a bottom hairline separator between rows.
    rowGrid: rowDivider,
    rowLine: rowDivider,
    rowMinimal: rowDivider,
    rowStriped: {},
    rowCompact: rowDivider,
    rowBordered: rowDivider,
    rowPrimaryHeader: rowDivider,

    // ─── Header row overrides ────────────────────────────────────────────────
    // Header rows replace the hairline with a heavier rule for clear hierarchy.
    rowHeaderGrid: {
      backgroundColor: t.colors.muted,
      borderBottomWidth: rule,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    rowHeaderLine: {
      borderBottomWidth: rule,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    rowHeaderMinimal: {
      borderBottomWidth: rule,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    rowHeaderStriped: {
      backgroundColor: t.colors.muted,
      borderBottomWidth: rule,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    rowHeaderCompact: {
      backgroundColor: t.colors.muted,
      borderBottomWidth: rule,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    rowHeaderBordered: {
      backgroundColor: t.colors.muted,
      borderBottomWidth: hairline,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    rowHeaderPrimaryHeader: {
      backgroundColor: t.colors.primary,
    },

    // ─── Footer row overrides ────────────────────────────────────────────────
    rowFooter: {
      borderTopWidth: rule,
      borderTopColor: borderColor,
      borderTopStyle: 'solid',
    },
    rowFooterStriped: {
      borderTopWidth: rule,
      borderTopColor: borderColor,
      borderTopStyle: 'solid',
      backgroundColor: t.colors.muted,
    },

    // ─── Zebra stripe ────────────────────────────────────────────────────────
    rowStripe: {
      backgroundColor: t.colors.muted,
    },

    // ─── Cell base ───────────────────────────────────────────────────────────
    // 6pt vertical, 10pt horizontal — balanced professional PDF table spacing.
    cell: {
      flex: 1,
      paddingVertical: cellPadV,
      paddingHorizontal: cellPadH,
      justifyContent: 'center',
    },
    cellFixed: {
      flex: 0,
    },

    // Cell variant padding overrides
    cellMinimal: {
      paddingVertical: spacing[1] + 1, // 5pt
      paddingHorizontal: spacing[2] - 2, // 6pt
    },
    cellStriped: {
      paddingVertical: cellPadV,
      paddingHorizontal: cellPadH,
    },
    // spacing[0.5] = 2pt — tests assert paddingVertical === 2
    cellCompact: {
      paddingVertical: cellPadVCompact,
      paddingHorizontal: cellPadHCompact,
    },
    cellBordered: {
      paddingVertical: cellPadV,
      paddingHorizontal: cellPadH,
    },
    cellPrimaryHeader: {
      paddingVertical: cellPadV,
      paddingHorizontal: cellPadH,
    },

    // Column divider for grid — hairline between cells, not on last cell
    cellGridBorder: {
      borderRightWidth: hairline,
      borderRightColor: borderColor,
      borderRightStyle: 'solid',
    },
    // Column divider for bordered — tests assert borderRightWidth === spacing[1] = 4
    cellBorderedBorder: {
      borderRightWidth: spacing[1],
      borderRightColor: borderColor,
      borderRightStyle: 'solid',
    },

    // ─── Cell text ───────────────────────────────────────────────────────────
    //
    // lineHeight: 1 is intentional and critical for all cell text styles.
    //
    // react-pdf adds EXTRA leading space below the text box when lineHeight > 1,
    // making rows appear to have more bottom padding than top padding. Since cells
    // already use symmetric paddingVertical on their <View> wrapper, text nodes
    // must use lineHeight: 1 so the text box is exactly fontSize tall with no
    // extra leading that would skew the visual vertical alignment.
    cellText: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.foreground,
    },

    // Header text styles — semibold for hierarchy
    cellTextHeaderGrid: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },
    cellTextHeaderLine: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },
    // Minimal uses muted header text (softer hierarchy)
    cellTextHeaderMinimal: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.mutedForeground,
      fontWeight: fontWeights.medium,
    },
    cellTextHeaderStriped: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },
    // Compact uses uppercase + small text for dense data headers
    cellTextHeaderCompact: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      lineHeight: 1,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
      textTransform: 'uppercase',
      letterSpacing: 0.6,
    },
    // Bordered uses bold text — tests assert fontWeight === 700
    cellTextHeaderBordered: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.foreground,
      fontWeight: fontWeights.bold,
    },
    // Primary-header uses xs uppercase on colored background
    cellTextHeaderPrimaryHeader: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      lineHeight: 1,
      color: t.colors.primaryForeground,
      fontWeight: fontWeights.semibold,
      textTransform: 'uppercase',
      letterSpacing: 0.6,
    },

    // Footer text — semibold for summary row prominence
    cellTextFooter: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: 1,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },

    // Compact data cell — xs font to match dense header
    cellTextCompact: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      lineHeight: 1,
      color: t.colors.foreground,
    },
  });
}

/** Table visual style variant. */
export type TableVariant =
  | 'line'
  | 'grid'
  | 'minimal'
  | 'striped'
  | 'compact'
  | 'bordered'
  | 'primary-header';

export interface TableProps {
  /** Custom styles to merge with component defaults */
  style?: Style;
  /** Content to render */
  children: React.ReactNode;
  /** Visual style variant that controls borders, backgrounds, and spacing. @default 'line' */
  variant?: TableVariant;
  /** Apply alternating row background colors to body rows. Automatically enabled for the `striped` variant. @default false */
  zebraStripe?: boolean;
  /** Prevent the entire table from splitting across PDF pages. Use for short tables that fit on one page. @default false */
  noWrap?: boolean;
}

export type TableSectionProps = PDFComponentProps;

export interface TableRowProps {
  /** Custom styles to merge with component defaults */
  style?: Style;
  /** Content to render */
  children: React.ReactNode;
  /** Render this row as a header row — applies bold text and variant header background. */
  header?: boolean;
  /** Render this row as a footer row — applies bold text and a top border. */
  footer?: boolean;
  /** Apply the zebra stripe background to this row. Set automatically by `Table` when `zebraStripe` is enabled. */
  stripe?: boolean;
  /** Visual variant inherited from the parent `Table`. Set automatically — do not pass manually. */
  variant?: TableVariant;
}

export interface TableCellProps {
  /** Custom styles to merge with component defaults */
  style?: Style;
  /** Content to render */
  children: React.ReactNode;
  /** Render this cell in header text style — bold, variant accent color. */
  header?: boolean;
  /** Render this cell in footer text style. */
  footer?: boolean;
  /** Horizontal text alignment within the cell. */
  align?: 'left' | 'center' | 'right';
  /** Fixed column width in PDF points or CSS-like string. When omitted the cell flex-grows. */
  width?: string | number;
  /** Visual variant inherited from the parent `TableRow`. Set automatically — do not pass manually. */
  variant?: TableVariant;
  /**
   * True when this is the last cell in its row.
   * Used internally to omit the right border on the last cell in `grid` / `bordered` variants.
   * @internal Set automatically by `TableRow` via `cloneElement` — do not pass manually.
   */
  _last?: boolean;
}
